    def figure240(self, data_dir: str | None = None) -> dict[str, Any]:
        """Run Chapter02 script `Figure240.py` with inlined code."""
        _ctx, pre_fig_nums, script_path = self._prepare_script_context(data_dir=data_dir)
        try:
            import matplotlib.pyplot as plt
            from skimage.io import imread
            from skimage.transform import rotate
            from skimage.util import img_as_float
            from libDIPUM.data_path import dip_data

            img_name = dip_data("letterT.tif")
            f_orig = imread(img_name)
            if f_orig.ndim == 3:
                f_orig = f_orig[:, :, 0]

            # f = f(1:8:end, 1:8:end);
            # Need lower resolution to show effects of rotation.
            f = f_orig[::8, ::8]

            # Convert to float for rotation logic consistency
            # (skimage usually returns float)
            f = img_as_float(f)

            # Rotation
            # MATLAB: imrotate(f, angle, method, bbox)
            # angle in degrees, counter-clockwise. MATLAB uses negative for clockwise?
            # MATLAB: + is CCW.
            # Script uses -21.
            # skimage rotate also uses degrees, + is CCW. So -21 matches.

            # Methods:
            # 'nearest' -> order=0
            # 'bilinear' -> order=1
            # 'bicubic' -> order=3

            # 'crop' behavior:
            # MATLAB 'crop': size of output is same as input.
            # skimage resize=False means "size required to fit whole image" (MATLAB 'loose').
            # resize=True means "resize to fit".
            # Wait, skimage `rotate(resize=False)` pads to fit the rotated image (default).
            # `resize=True` in skimage means "Change dimensions".
            # Actually:
            # skimage.transform.rotate(image, angle, resize=False, ...) -> Output shape is input shape?
            # No, documentation says: "If True, output image size will be adjusted so that the entire rotated image fits."
            # So `resize=False` keeps input shape (which matches MATLAB 'crop').

            frn = rotate(f, -21, resize=False, order=0)
            frbl = rotate(f, -21, resize=False, order=1)
            frbc = rotate(f, -21, resize=False, order=3)

            # Display
            fig, axes = plt.subplots(2, 2, figsize=(10, 10))

            axes[0, 0].imshow(f, cmap="gray")
            axes[0, 0].set_title("Original (Subsampled)")
            axes[0, 0].axis("off")

            axes[0, 1].imshow(frn, cmap="gray")
            axes[0, 1].set_title("Nearest Neighbor")
            axes[0, 1].axis("off")

            axes[1, 0].imshow(frbl, cmap="gray")
            axes[1, 0].set_title("Bilinear")
            axes[1, 0].axis("off")

            axes[1, 1].imshow(frbc, cmap="gray")
            axes[1, 1].set_title("Bicubic")
            axes[1, 1].axis("off")

            plt.tight_layout()
            plt.savefig("Figure240.png")
            print("Saved Figure240.png")
            plt.show()
        finally:
            self._restore_script_context(_ctx, data_dir=data_dir)
        return self._collect_new_figures(pre_fig_nums)

    def figure242(self, data_dir: str | None = None) -> dict[str, Any]:
        """Run Chapter02 script `Figure242.py` with inlined code."""
        _ctx, pre_fig_nums, script_path = self._prepare_script_context(data_dir=data_dir)
        try:
            import numpy as np
            import matplotlib.pyplot as plt
            from skimage.io import imread
            from skimage.util import img_as_float
            from skimage.transform import AffineTransform, warp, estimate_transform
            from libDIPUM.data_path import dip_data

            # Data
            img_name = dip_data("characterTestPattern688.tif")
            f_orig = imread(img_name)
            if f_orig.ndim == 3:
                f_orig = f_orig[:, :, 0]
            f = img_as_float(f_orig)

            h, w = f.shape

            # Generate sheared image `gd`
            # MATLAB: shear = [1 .4 0; .05 1 0; 0 0 1];
            # This matrix is in MATLAB's post-multiply convention for [x y 1].
            # x' = x + 0.05y
            # y' = 0.4x + y
            # Skimage AffineTransform matrix M applies to [x; y; 1] (pre-multiply).
            # [x'; y'; 1] = M * [x; y; 1]
            # x' = 1*x + 0.05*y + 0
            # y' = 0.4*x + 1*y + 0
            # So M = [[1, 0.05, 0], [0.4, 1, 0], [0, 0, 1]]

            shear_matrix = np.array([[1, 0.05, 0], [0.4, 1, 0], [0, 0, 1]])

            # Calculate output bounding box to simulate imtransform 'fully contained' behavior
            corners = np.array([[0, 0], [w, 0], [w, h], [0, h]])

            # Transform corners
            # AffineTransform operates on (x,y)
            tform_shear = AffineTransform(matrix=shear_matrix)
            corners_transformed = tform_shear(corners)

            min_x = corners_transformed[:, 0].min()
            max_x = corners_transformed[:, 0].max()
            min_y = corners_transformed[:, 1].min()
            max_y = corners_transformed[:, 1].max()

            out_w = int(np.ceil(max_x - min_x))
            out_h = int(np.ceil(max_y - min_y))

            # We want output image (0..out_w, 0..out_h) to map to the transformed coords.
            # Specifically, output pixel (u,v) should correspond to world coord (u + min_x, v + min_y).
            # warp needs inverse_map: output_coord -> input_coord.
            # input_coord = inverse_shear(output_coord_in_shear_space)
            #             = inverse_shear(pixel_u + min_x, pixel_v + min_y)
            #             = inverse_shear(pixel + offset)
            # So effective transform for warp is Translation(offset) + InverseShear ??
            # Actually, easiest is to compose transforms.
            # We want T_warp such that T_warp(pixel) = input_pixel.
            # pixel -> (add min) -> sheared_coord -> (inverse shear) -> input_pixel.

            translation_matrix = np.array([[1, 0, min_x], [0, 1, min_y], [0, 0, 1]])
            # Total M for [x'; y'; 1] = T * [x; y; 1]
            # We want x_shear = x_pixel + min_x.
            # This is T_trans * x_pixel.

            # So forward map from Pixel -> Sheared is Translation(min_x, min_y).
            # Then Sheared -> Input is Shear.inverse.
            # So Pixel -> Input = Shear.inverse * Translation.

            t_trans = AffineTransform(translation=(min_x, min_y))
            # Combine: apply translation first, then inverse shear?
            # logical chain: p_out --(trans)--> p_shear --(inv_shear)--> p_in.

            # Skimage warp takes inverse_map.
            # If we pass a transform, it assumes it maps output->input?
            # Docs: "Inverse map... transforms coordinates in the output image into... input image".
            # So yes, we construct the total transform T = Shear_inv * Translation.
            # Note: Matrix multiplication order. M2 * M1 * v applies M1 then M2.
            # We want Translation then InverseShear.
            # So Matrix = M_inv_shear @ M_trans.

            m_inv_shear = np.linalg.inv(shear_matrix)
            m_trans = np.array([[1, 0, min_x], [0, 1, min_y], [0, 0, 1]])

            map_matrix = m_inv_shear @ m_trans
            tform_warp = AffineTransform(matrix=map_matrix)

            gd = warp(f, tform_warp, output_shape=(out_h, out_w), order=1)

            # Compute registration
            # Control points (x, y)
            base_points = np.array(
                [
                    [114.9692, 109.4923],
                    [618.2154, 75.7538],
                    [600.3538, 610.9385],
                    [75.0923, 633.4308],
                ]
            )

            input_points = np.array(
                [
                    [118.5971, 155.0846],
                    [623.2462, 322.6837],
                    [629.7279, 851.9587],
                    [104.7077, 663.9885],
                ]
            )

            # Estimate transform mapping input (gd) -> base (f)
            tform_reg = estimate_transform("affine", src=input_points, dst=base_points)

            # Back transformation
            # We want to warp `gd` to match `f`.
            # Target shape is f.shape.
            # We iterate over `f` pixels (base).
            # We need corresponding source pixels in `gd` (input).
            # Source = Inverse(Transform(Input->Base)) * Dest ?
            # Wait. `tform_reg` maps Input -> Base.
            # We want Base -> Input (to sample from gd).
            # So we need Inverse(tform_reg).
            # warp(gd, inverse_map=tform_reg.inverse, output_shape=f.shape)

            g = warp(gd, tform_reg.inverse, output_shape=f.shape, order=1)

            # Difference
            dif = f - g
            # abs difference usually for display
            dif_abs = np.abs(dif)

            # Display
            fig, axes = plt.subplots(2, 2, figsize=(10, 10))

            axes[0, 0].imshow(f, cmap="gray")
            axes[0, 0].set_title("Original Image f")
            axes[0, 0].axis("off")

            axes[0, 1].imshow(gd, cmap="gray")
            axes[0, 1].set_title("Geometrically Distorted gd")
            axes[0, 1].axis("off")

            axes[1, 0].imshow(g, cmap="gray")
            axes[1, 0].set_title("Recovered Image g")
            axes[1, 0].axis("off")

            axes[1, 1].imshow(dif_abs, cmap="gray")
            axes[1, 1].set_title("Difference |f - g|")
            axes[1, 1].axis("off")

            plt.tight_layout()
            plt.savefig("Figure242.png")
            print("Saved Figure242.png")
            plt.show()
        finally:
            self._restore_script_context(_ctx, data_dir=data_dir)
        return self._collect_new_figures(pre_fig_nums)

    def figure245(self, data_dir: str | None = None) -> dict[str, Any]:
        """Run Chapter02 script `Figure245.py` with inlined code."""
        _ctx, pre_fig_nums, script_path = self._prepare_script_context(data_dir=data_dir)
        try:
            import numpy as np
            import matplotlib.pyplot as plt
            from skimage.io import imread
            from skimage.util import img_as_float
            from scipy.fft import fft2, fftshift
            from libDIPUM.imnoise3 import imnoise3
            from libDIPUM.cnotch import cnotch
            from libDIP.intScaling4e import intScaling4e
            from libDIPUM.dftfilt import dftfilt
            from libDIPUM.data_path import dip_data

            # Data
            img_path = dip_data("astronaut.tif")

            # Load and convert to double
            f = img_as_float(imread(img_path))
            M, N = f.shape

            # Generate sinusoidal noise
            # [r, R, S] = imnoise3(M, N, [25 25], 0.3);
            # Note: imnoise3 returns noise pattern r.
            # C = [25, 25] means impulses at (u0, v0) = (25, 25) relative to center? or absolute?
            # Imnoise3 logic usually takes C as coordinates of impulses.
            # Let's assume the Python port follows MATLAB's imnoise3 signature: [r, R, S] = imnoise3(M, N, C, A, B)
            # A=0.3 is amplitude.
            r, R, S = imnoise3(M, N, [[25, 25]], [0.3])
            # Note: imnoise3 implementation might vary. If it takes list of coords and list of Amps.
            # Passing single list [25, 25] might define one impulse pair.

            g = f + r

            # Scale g for display/web as per MATLAB comment (improving contrast)
            gs = intScaling4e(g)

            # Compute spectrum
            F = fft2(g)
            G = fftshift(np.abs(F))
            # Log transform for visualization
            Glog = intScaling4e(1 + np.log(G))

            # Create notch filters
            # M=1650, N=2000 roughly? (Astronaut is likely smaller, 512x512?)
            # Center is M/2, N/2 (0-indexed).
            # MATLAB: M/2+1, N/2+1.
            # MATLAB: Impulse at center + 25.
            # Python: Center is M//2, N//2.
            # Impulse location = (M//2 + 25, N//2 + 25).
            # cnotch handles symmetry.

            # H = cnotch('ideal', 'reject', M, N, [M/2+1+25, N/2+1+25], 2);
            # In Python, we might provide center + Offset.
            # Let's calculate the exact center coords.
            u_impulse = M // 2 + 25
            v_impulse = N // 2 + 25

            # cnotch parameters (type, mode, M, N, C, D0, n)
            # C is list of coordinates.
            H = cnotch("ideal", "reject", M, N, [[u_impulse, v_impulse]], 2)

            # Scale filter for display
            Hc = intScaling4e(fftshift(H))  # H is usually centered already by cnotch?
            # Typically cnotch returns centered filter H(u,v) corresponding to centered spectrum?
            # Wait, MATLAB cnotch returns H matching centered spectrum if we use dftfilt with centered?
            # Let's check cnotch/dftfilt implementation.
            # Usually: dftfilt(f, H) expects H to be aligned with fft2(f) (uncentered) OR centered.
            # Standard dftfilt often handles centering/uncentering.
            # If cnotch returns centered H, we might need to ifftshift it before dftfilt if dftfilt expects uncentered.
            # Or dftfilt checks.
            # I'll check dftfilt.py content.

            # Apply filter
            gf_raw = dftfilt(g, H)
            gf = intScaling4e(gf_raw)

            # Display
            fig, axes = plt.subplots(2, 2, figsize=(10, 10))
            axes = axes.flatten()

            axes[0].imshow(gs, cmap="gray")
            axes[0].set_title("Noisy Image")
            axes[0].axis("off")

            axes[1].imshow(Glog, cmap="gray")
            axes[1].set_title("Spectrum (Log)")
            axes[1].axis("off")

            axes[2].imshow(Hc, cmap="gray")
            axes[2].set_title("Notch Filter")
            axes[2].axis("off")

            axes[3].imshow(gf, cmap="gray")
            axes[3].set_title("Restored Image")
            axes[3].axis("off")

            plt.tight_layout()
            plt.savefig("Figure245.png")
            print("Saved Figure245.png")

            plt.show()
        finally:
            self._restore_script_context(_ctx, data_dir=data_dir)
        return self._collect_new_figures(pre_fig_nums)

