            z = np.arange(1, 257)
            # trapezmf(z, 0, 0, 64, 256)
            # This means:
            # a=0, b=0 (flat start)
            # c=64 (start of ramp down)
            # d=256 (end of ramp down)
            # So flat 1.0 from 0 to 64, then ramp down to 0 at 256.
            fun = trapezmf(z, 0, 0, 64, 256)

