            def gaussian_1d(size: Any, sigma: Any):
                """gaussian_1d."""
                radius = (size - 1) // 2
                x = np.arange(-radius, radius + 1, dtype=np.float64)
                w = np.exp(-(x**2) / (2.0 * sigma * sigma))
                w /= np.sum(w)
                return w

            # Separable kernels equivalent to normalized 2D Gaussian kernels
            w187 = gaussian_1d(187, 31.0)
