            # 2. Radon
            axes[0, 1].imshow(R, cmap="gray", aspect="auto")
            axes[0, 1].set_title("Radon transform")
            axes[0, 1].set_xlabel("theta")
            axes[0, 1].set_ylabel("rho")

            # 3. Ram-Lak
            axes[1, 0].imshow(fHat_RamLak, cmap="gray")
            axes[1, 0].set_title("RAM-LAK")
