            ax.imshow(ia.iagsurf(c), cmap="gray")
            ax.set_title("Surf(c)")
            ax.axis("off")

            ax = fig2.add_subplot(2, 2, 2)
            plt.sca(ax)
            ax.imshow(_imshow_ready(ia.iagshow(ia.iagsurf(c), d)))
            ax.set_title("Surf(c), d")
            ax.axis("off")

            ax = fig2.add_subplot(2, 2, 3)
