            axes[0, 1].imshow(emap, cmap="gray")
            axes[0, 1].axis("off")

            axes[1, 0].quiver(np.flipud(FTy[::2, ::2]), np.flipud(-FTx[::2, ::2]))
            axes[1, 0].axis("off")

            axes[1, 1].imshow(f, cmap="gray")
            axes[1, 1].axis("off")
            plt.sca(axes[1, 1])
